class DisjointSet
  @parent : Array(Int64)
  @rank : Array(Int64)

  def initialize(size)
    @parent = (0...size).to_a.map(&.to_i64)
    @rank = Array.new(size, 0_i64)
  end

  def find(u)
    if @parent[u] != u
      @parent[u] = find(@parent[u])
    end
    @parent[u]
  end

  def union(u, v)
    u_root = find(u)
    v_root = find(v)
    return if u_root == v_root

    if @rank[u_root] < @rank[v_root]
      @parent[u_root] = v_root
    elsif @rank[u_root] > @rank[v_root]
      @parent[v_root] = u_root
    else
      @parent[v_root] = u_root
      @rank[u_root] += 1
    end
  end
end

def solve(n : Int64, edges : Array(Array(Int64)), k : Int64) : Int64
  return 0_i64 if edges.empty?

  sorted_edges = edges.sort_by { |edge| edge[2] }
  ds = DisjointSet.new(n)
  max_cost = 0_i64
  components = n

  sorted_edges.each do |edge|
    u, v, w = edge
    if components <= k
      break
    end
    if ds.find(u) != ds.find(v)
      ds.union(u, v)
      components -= 1
      max_cost = w if w > max_cost
    end
  end

  max_cost
end
